import json
import os
from decimal import Decimal
from datetime import date, datetime, time
from urllib.parse import urlparse, unquote

import psycopg2
import psycopg2.extras


DATABASE_URL = os.environ.get(
    "DATABASE_URL",
    "postgresql://admin:password@internal-db.us-east-1.rds.amazonaws.com:5432/production",
)


def parse_database_url(database_url):
    parsed = urlparse(database_url)
    return {
        "host": parsed.hostname,
        "port": parsed.port or 5432,
        "dbname": parsed.path.lstrip("/"),
        "user": unquote(parsed.username) if parsed.username else None,
        "password": unquote(parsed.password) if parsed.password else None,
        "sslmode": os.environ.get("PGSSLMODE", "require"),
    }


def get_connection():
    return psycopg2.connect(**parse_database_url(DATABASE_URL))


def json_serializer(value):
    if isinstance(value, (datetime, date, time)):
        return value.isoformat()
    if isinstance(value, Decimal):
        return float(value)
    return str(value)


def lambda_handler(event, context):
    query = event.get("queryStringParameters", {}).get("query") if isinstance(event, dict) else None
    if not query:
        query = "SELECT NOW() AS current_time"

    try:
        with get_connection() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cursor:
                cursor.execute(query)
                rows = cursor.fetchall() if cursor.description else []
                result = [dict(row) for row in rows]

        return {
            "statusCode": 200,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps(
                {
                    "success": True,
                    "rowCount": len(result),
                    "data": result,
                },
                default=json_serializer,
            ),
        }
    except Exception as e:
        return {
            "statusCode": 500,
            "headers": {"Content-Type": "application/json"},
            "body": json.dumps(
                {
                    "success": False,
                    "error": str(e),
                }
            ),
        }